class Board:
    def __init__(self):
        self.board = [['.' for _ in range(8)] for _ in range(8)]
        self.initialize_board()

    def initialize_board(self):
        # Initialize the board with checkers pieces
        positions = [(i, j) for i in range(3, 5) for j in range(0, 8, 2)] + \
                    [(i, j+1) for i in range(4, 6) for j in range(7, -1, -2)]
        for pos in positions:
            self.board[pos[0]][pos[1]] = 'B'
        for pos in positions[::-1]:
            self.board[pos[0]][pos[1]] = 'W'

    def print_board(self):
        # Print the board with row and column labels
        print("   ", end="")
        for i in range(8):
            print(f"{chr(i + 97)} ", end="")
        print("\n")
        for i, row in enumerate(self.board):
            print(f"{i+1} {row}\n")

    def move_piece(self, from_pos, to_pos):
        # Move a piece from one position to another
        if self.board[from_pos[0]][from_pos[1]] == '.':
            raise ValueError("No piece at the source position")
        if self.board[to_pos[0]][to_pos[1]] != '.':
            raise ValueError("Destination position already occupied")
        self.board[to_pos[0]][to_pos[1]] = self.board[from_pos[0]][from_pos[1]]
        self.board[from_pos[0]][from_pos[1]] = '.'

