class Game:
    def __init__(self):
        self.board = Board()
        self.current_player = 'W'

    def start(self):
        # Start the game loop
        while True:
            self.board.print_board()
            try:
                move = input(f"Player {self.current_player}, enter your move (e.g., a1 b2): ")
                from_pos = (int(move[1]) - 1, ord(move[0].lower()) - 97)
                to_pos = (int(move[3]) - 1, ord(move[2].lower()) - 97)
                self.board.move_piece(from_pos, to_pos)
                self.current_player = 'B' if self.current_player == 'W' else 'W'
            except Exception as e:
                print(f"Invalid move: {e}")
